 27	const flushInterval = 500;
 28	
 29	// We have to check different properties depending on whether events were
 30	// created with the core/v1 events API or the new events.k8s.io API.
 31	const getFirstTime = (event) => event.firstTimestamp || event.eventTime;
 32	export const getLastTime = (event) => {
 33	  const lastObservedTime = event.series ? event.series.lastObservedTime : null;
 34	  return event.lastTimestamp || lastObservedTime || event.eventTime;
 35	};
 36	export const sortEvents = (events) => {
 37	  return _.orderBy(
 38	    events,
 39	    [getLastTime, getFirstTime, 'name'],
 40	    ['desc', 'desc', 'asc'],
 41	  );
 42	};
 43	
 44	// Predicate function to filter by event "type" (normal, warning, or all)
 45	export const typeFilter = (eventType, event) => {
 46	  if (eventType === 'all') {
 47	    return true;
 48	  }
 49	  const { type = 'normal' } = event;
 50	  return type.toLowerCase() === eventType;
 51	};
 52	
 53	const kindFilter = (reference, { involvedObject }) => {
 54	  if (!reference) {
 55	    return true;
 56	  }
 57	  const kinds = reference.split(',');
 58	  return kinds.some((ref) => {
 59	    if (!isGroupVersionKind(ref)) {
 60	      return involvedObject.kind === ref;
 61	    }
 62	    // Use `referenceFor` to resolve `apiVersion` when missing from `involvedObject`.
 63	    // We need `apiVersion` to get the group.
 64	    const involvedObjectRef = referenceFor(involvedObject);
 65	    if (!involvedObjectRef) {
 66	      return false;
 67	    }
 68	    // Only check the group and kind, not the API version, so that we catch
 69	    // events for the same resource under a different API version.
 70	    return (
 71	      involvedObject.kind === kindForReference(ref) &&
 72	      apiGroupForReference(involvedObjectRef) === apiGroupForReference(ref)
 73	    );
 74	  });
 75	};
