 92	  const lastTime = getLastTime(event);
 93	  const count = series ? series.count : event.count;
 94	  const canlistNode = useFlag(FLAGS.CAN_LIST_NODE);
 95	  // Events in v1beta1 apiVersion store the information about the reporting component
 96	  // in the 'source.component' field. Events in v1 apiVersion are storing the information
 97	  // in the `reportingComponent` field.
 98	  // Unfortunatelly we cannot determine which field to use based on the apiVersion since
 99	  // v1beta1 is internally converted to v1.
100	  const component = source.component ? source.component : reportingComponent;
101	
102	  return (
103	    <div
104	      className={classNames('co-sysevent', {
105	        'co-sysevent--warning': isWarning,
106	      })}
107	      data-test={isWarning ? 'event-warning' : 'event'}
108	    >
109	      <div className="co-sysevent__icon-box">
110	        <i className="co-sysevent-icon" title={tooltipMsg} />
111	        <div className="co-sysevent__icon-line" />
112	      </div>
113	      <div className="co-sysevent__box" role="gridcell">
114	        <div className="co-sysevent__header">
115	          <div className="co-sysevent__subheader">
116	            <ResourceLink
117	              className="co-sysevent__resourcelink"
118	              kind={referenceFor(obj)}
119	              namespace={obj.namespace}
120	              name={obj.name}
121	            />
122	            {obj.namespace && (
123	              <ResourceLink
124	                className="co-sysevent__resourcelink hidden-xs"
125	                kind="Namespace"
126	                name={obj.namespace}
127	              />
128	            )}
129	            {lastTime && (
130	              <Timestamp
131	                className="co-sysevent__timestamp"
132	                timestamp={lastTime}
133	              />
134	            )}
135	          </div>
136	          <div className="co-sysevent__details">
137	            <small className="co-sysevent__source">
138	              {component !== 'kubelet' &&
139	                t('Generated from {{ sourceComponent }}', {
140	                  sourceComponent: component,
141	                })}
142	              {component === 'kubelet' && canlistNode && (
143	                <Trans ns="plugin__pipelines-console-plugin">
144	                  Generated from {{ sourceComponent: component }} on{' '}
145	                  <Link to={resourcePathFromModel(NodeModel, source.host)}>
146	                    {{ sourceHost: source.host }}
147	                  </Link>
148	                </Trans>
149	              )}
150	              {component === 'kubelet' &&
151	                !canlistNode &&
152	                t('Generated from {{ sourceComponent }} on {{ sourceHost }}', {
153	                  sourceComponent: component,
