163	                    simple={true}
164	                    omitSuffix={true}
165	                  />
166	                </small>
167	              </Trans>
168	            )}
169	            {count > 1 && !firstTime && (
170	              <Trans ns="plugin__pipelines-console-plugin">
171	                <small className="co-sysevent__count text-secondary">
172	                  {{ eventCount: count }} times
173	                </small>
174	              </Trans>
175	            )}
176	          </div>
177	        </div>
178	        <div className="co-sysevent__message">{message}</div>
179	      </div>
180	    </div>
