183	
184	export const NoEvents = () => {
185	  const { t } = useTranslation('plugin__pipelines-console-plugin');
186	  return (
187	    <Box className="co-sysevent-stream__status-box-empty">
188	      <div className="cp-text-align-center cos-status-box__detail">
189	        {t('No events')}
190	      </div>
191	    </Box>
192	  );
193	};
194	
195	export const NoMatchingEvents = ({ allCount }) => {
196	  const { t } = useTranslation('plugin__pipelines-console-plugin');
197	  return (
198	    <Box className="co-sysevent-stream__status-box-empty">
199	      <div className="cos-status-box__title">{t('No matching events')}</div>
200	      <div className="cp-text-align-center cos-status-box__detail">
201	        {allCount >= maxMessages
202	          ? t('{{count}}+ event exist, but none match the current filter', {
203	              count: maxMessages,
204	            })
205	          : t('{{count}} event exist, but none match the current filter', {
206	              count: allCount,
207	            })}
208	      </div>
209	    </Box>
210	  );
211	};
212	
213	export const ErrorLoadingEvents = () => {
214	  const { t } = useTranslation('plugin__pipelines-console-plugin');
215	  return (
216	    <Box>
217	      <div className="cos-status-box__title cos-error-title">
218	        {t('Error loading events')}
219	      </div>
220	      <div className="cos-status-box__detail cp-text-align-center">
221	        {t(
222	          'An error occurred during event retrieval. Attempting to reconnect...',
223	        )}
224	      </div>
225	    </Box>
226	  );
227	};
228	
229	const EventStream = ({
230	  namespace,
231	  fieldSelector,
232	  mock,
233	  resourceEventStream,
234	  kind,
235	  type,
236	  filter,
237	  textFilter,
238	}) => {
239	  const { t } = useTranslation('plugin__pipelines-console-plugin');
240	  const [active, setActive] = React.useState(true);
241	  const [sortedEvents, setSortedEvents] = React.useState([]);
242	  const [error, setError] = React.useState(null);
243	  const [loading, setLoading] = React.useState(true);
244	  const ws = React.useRef(null);
245	
246	  const filteredEvents = React.useMemo(() => {
247	    return filterEvents(sortedEvents, { kind, type, filter, textFilter }).slice(
248	      0,
249	      maxMessages,
250	    );
251	  }, [sortedEvents, kind, type, filter, textFilter]);
252	
253	  // Handle websocket setup and teardown when dependent props change
254	  React.useEffect(() => {
255	    ws.current?.destroy();
256	    if (!mock) {
257	      const webSocketID = `${namespace || 'all'}-sysevents`;
258	      const watchURLOptions = {
259	        ...(namespace ? { ns: namespace } : {}),
260	        ...(fieldSelector
261	          ? {
262	              queryParams: {
263	                fieldSelector: encodeURIComponent(fieldSelector),
264	              },
265	            }
266	          : {}),
267	      };
268	      const path = watchURL(EventModel, watchURLOptions);
269	      const webSocketOptions = {
270	        host: 'auto',
271	        reconnect: true,
272	        path,
273	        jsonParse: true,
274	        bufferFlushInterval: flushInterval,
275	        bufferMax: maxMessages,
276	        subprotocols: undefined,
277	      };
278	
279	      ws.current = new WSFactory(webSocketID, webSocketOptions)
280	        .onbulkmessage((messages) => {
281	          // Make one update to state per batch of events.
282	          setSortedEvents((currentSortedEvents) => {
283	            const topEvents = currentSortedEvents.slice(0, maxMessages);
284	            const batch = messages.reduce(
285	              (acc, { object, type: eventType }) => {
286	                const uid = object.metadata.uid;
287	                switch (eventType) {
288	                  case 'ADDED':
289	                  case 'MODIFIED':
290	                    if (acc[uid] && acc[uid].count > object.count) {
291	                      // We already have a more recent version of this message stored, so skip this one
292	                      return acc;
293	                    }
294	                    return { ...acc, [uid]: object };
295	                  case 'DELETED':
296	                    return _.omit(acc, uid);
297	                  default:
298	                    // eslint-disable-next-line no-console
299	                    console.error(`UNHANDLED EVENT: ${eventType}`);
300	                    return acc;
301	                }
302	              },
303	              _.keyBy(topEvents, 'metadata.uid'),
304	            );
305	            return sortEvents(batch);
306	          });
307	        })
308	        .onopen(() => {
309	          setError(false);
310	          setLoading(false);
311	        })
312	        .onclose((evt) => {
313	          if (evt?.wasClean === false) {
314	            setError(evt.reason || t('Connection did not close cleanly.'));
315	          }
316	        })
317	        .onerror(() => {
318	          setError(true);
319	        });
320	    }
321	    return () => {
322	      ws.current?.destroy();
323	    };
324	  }, [namespace, fieldSelector, mock, t]);
325	
326	  // Pause/unpause the websocket when the active state changes
327	  React.useEffect(() => {
328	    if (active) {
329	      ws.current?.unpause();
330	    } else {
331	      ws.current?.pause();
332	    }
333	  }, [active]);
334	
335	  const toggleStream = () => {
336	    setActive((prev) => !prev);
337	  };
338	
339	  const count = filteredEvents.length;
340	  const allCount = sortedEvents.length;
341	  const noEvents = allCount === 0;
342	  const noMatches = allCount > 0 && count === 0;
343	  let sysEventStatus, statusBtnTxt;
344	
345	  if (noEvents || mock || (noMatches && resourceEventStream)) {
346	    sysEventStatus = <NoEvents />;
347	  }
348	  if (noMatches && !resourceEventStream) {
349	    sysEventStatus = <NoMatchingEvents allCount={allCount} />;
350	  }
351	
352	  if (error) {
353	    statusBtnTxt = (
354	      <span className="co-sysevent-stream__connection-error">
355	        {_.isString(error)
356	          ? t('Error connecting to event stream: { error }', {
357	              error,
358	            })
359	          : t('Error connecting to event stream')}
360	      </span>
361	    );
362	    sysEventStatus = <ErrorLoadingEvents />;
363	  } else if (loading) {
364	    statusBtnTxt = <span>{t('Loading events...')}</span>;
365	    sysEventStatus = <Loading />;
366	  } else if (active) {
367	    statusBtnTxt = <span>{t('Streaming events...')}</span>;
368	  } else {
369	    statusBtnTxt = <span>{t('Event stream is paused.')}</span>;
370	  }
371	
372	  const klass = classNames('co-sysevent-stream__timeline', {
373	    'co-sysevent-stream__timeline--empty': !allCount || !count,
374	  });
375	  const messageCount =
376	    count < maxMessages
377	      ? t('Showing {{count}} event', { count })
378	      : t('Showing most recent {{count}} event', { count });
379	
380	  return (
381	    <PageSection isFilled variant="light">
382	      <div className="co-sysevent-stream">
383	        <div className="co-sysevent-stream__status">
384	          <div className="co-sysevent-stream__timeline__btn-text">
385	            {statusBtnTxt}
386	          </div>
387	          <div
388	            className="co-sysevent-stream__totals text-secondary"
389	            data-test="event-totals"
390	          >
391	            {messageCount}
392	          </div>
393	        </div>
394	
395	        <div className={klass}>
396	          <TogglePlay
397	            active={active}
398	            onClick={toggleStream}
399	            className="co-sysevent-stream__timeline__btn"
400	          />
401	          <div className="co-sysevent-stream__timeline__end-message">
402	            {t('Older events are not stored.')}
403	          </div>
404	        </div>
405	        {count > 0 && (
406	          <EventStreamList events={filteredEvents} EventComponent={Inner} />
407	        )}
408	        {sysEventStatus}
409	      </div>
410	    </PageSection>
411	  );
412	};
413	
414	EventStream.defaultProps = {
415	  type: 'all',
416	  kind: '',
417	  mock: false,
418	};
419	
420	EventStream.propTypes = {
421	  type: PropTypes.string,
422	  filter: PropTypes.array,
423	  kind: PropTypes.string.isRequired,
424	  mock: PropTypes.bool,
425	  namespace: namespaceProptype,
426	  showTitle: PropTypes.bool,
427	  textFilter: PropTypes.string,
428	};
429	
430	const filterEvents = (messages, { kind, type, filter, textFilter }) => {
431	  // Don't use `fuzzy` because it results in some surprising matches in long event messages.
432	  // Instead perform an exact substring match on each word in the text filter.
433	  const words = _.uniq(_.toLower(textFilter).match(/\S+/g)).sort((a, b) => {
434	    // Sort the longest words first.
435	    return b.length - a.length;
436	  });
437	
438	  const textMatches = (obj) => {
439	    if (_.isEmpty(words)) {
440	      return true;
441	    }
442	    const name = _.get(obj, 'involvedObject.name', '');
443	    const message = _.toLower(obj.message);
444	    return _.every(
445	      words,
446	      (word) => name.indexOf(word) !== -1 || message.indexOf(word) !== -1,
447	    );
448	  };
449	
450	  const f = (obj) => {
451	    if (type && !typeFilter(type, obj)) {
452	      return false;
453	    }
454	    if (kind && !kindFilter(kind, obj)) {
455	      return false;
456	    }
457	    if (filter && !filter.some((flt) => flt(obj.involvedObject, obj))) {
458	      return false;
459	    }
460	    if (!textMatches(obj)) {
461	      return false;
462	    }
463	    return true;
464	  };
465	
466	  return _.filter(messages, f);
467	};
468	
469	export const ResourceEventStream_ = ({
470	  obj: {
471	    kind,
472	    metadata: { name, namespace, uid },
473	  },
474	}) => (
475	  <EventStream
476	    fieldSelector={`involvedObject.uid=${uid},involvedObject.name=${name},involvedObject.kind=${kind}`}
477	    namespace={namespace}
478	    resourceEventStream
479	  />
480	);
481	
482	export { ResourceEventStream_ as ResourceEventStream };
483	
484	export const ResourcesEventStream = ({ filters, namespace }) => (
485	  <EventStream filter={filters} resourceEventStream namespace={namespace} />
486	);
487	
488	/**
489	 * @typedef {import('@console/dynamic-plugin-sdk/src/extensions').ResourceEventStreamProps} ResourceEventStreamProps
490	 * @augments React.FC<ResourceEventStreamProps>
491	 */
492	export const WrappedResourceEventStream = ({ resource }) => (
493	  <ResourceEventStream_ obj={resource} />
494	);
495	
496	export default ResourceEventStream_;

