229	const EventStream = ({
230	  namespace,
231	  fieldSelector,
232	  mock,
233	  resourceEventStream,
234	  kind,
235	  type,
236	  filter,
237	  textFilter,
238	}) => {
239	  const { t } = useTranslation('plugin__pipelines-console-plugin');
240	  const [active, setActive] = React.useState(true);
241	  const [sortedEvents, setSortedEvents] = React.useState([]);
242	  const [error, setError] = React.useState(null);
243	  const [loading, setLoading] = React.useState(true);
244	  const ws = React.useRef(null);
245	
246	  const filteredEvents = React.useMemo(() => {
247	    return filterEvents(sortedEvents, { kind, type, filter, textFilter }).slice(
248	      0,
249	      maxMessages,
250	    );
251	  }, [sortedEvents, kind, type, filter, textFilter]);
252	
253	  // Handle websocket setup and teardown when dependent props change
254	  React.useEffect(() => {
255	    ws.current?.destroy();
256	    if (!mock) {
257	      const webSocketID = `${namespace || 'all'}-sysevents`;
258	      const watchURLOptions = {
259	        ...(namespace ? { ns: namespace } : {}),
260	        ...(fieldSelector
261	          ? {
262	              queryParams: {
263	                fieldSelector: encodeURIComponent(fieldSelector),
264	              },
265	            }
266	          : {}),
267	      };
268	      const path = watchURL(EventModel, watchURLOptions);
269	      const webSocketOptions = {
270	        host: 'auto',
271	        reconnect: true,
272	        path,
273	        jsonParse: true,
274	        bufferFlushInterval: flushInterval,
275	        bufferMax: maxMessages,
276	        subprotocols: undefined,
277	      };
278	
279	      ws.current = new WSFactory(webSocketID, webSocketOptions)
280	        .onbulkmessage((messages) => {
281	          // Make one update to state per batch of events.
282	          setSortedEvents((currentSortedEvents) => {
283	            const topEvents = currentSortedEvents.slice(0, maxMessages);
284	            const batch = messages.reduce(
285	              (acc, { object, type: eventType }) => {
286	                const uid = object.metadata.uid;
287	                switch (eventType) {
288	                  case 'ADDED':
289	                  case 'MODIFIED':
290	                    if (acc[uid] && acc[uid].count > object.count) {
291	                      // We already have a more recent version of this message stored, so skip this one
292	                      return acc;
293	                    }
294	                    return { ...acc, [uid]: object };
295	                  case 'DELETED':
296	                    return _.omit(acc, uid);
297	                  default:
298	                    // eslint-disable-next-line no-console
299	                    console.error(`UNHANDLED EVENT: ${eventType}`);
300	                    return acc;
301	                }
302	              },
303	              _.keyBy(topEvents, 'metadata.uid'),
304	            );
305	            return sortEvents(batch);
306	          });
307	        })
308	        .onopen(() => {
309	          setError(false);
310	          setLoading(false);
311	        })
312	        .onclose((evt) => {
313	          if (evt?.wasClean === false) {
314	            setError(evt.reason || t('Connection did not close cleanly.'));
315	          }
316	        })
317	        .onerror(() => {
318	          setError(true);
319	        });
320	    }
321	    return () => {
322	      ws.current?.destroy();
323	    };
324	  }, [namespace, fieldSelector, mock, t]);
325	
326	  // Pause/unpause the websocket when the active state changes
327	  React.useEffect(() => {
328	    if (active) {
329	      ws.current?.unpause();
330	    } else {
331	      ws.current?.pause();
332	    }
333	  }, [active]);
334	
335	  const toggleStream = () => {
336	    setActive((prev) => !prev);
337	  };
338	
339	  const count = filteredEvents.length;
340	  const allCount = sortedEvents.length;
341	  const noEvents = allCount === 0;
342	  const noMatches = allCount > 0 && count === 0;
343	  let sysEventStatus, statusBtnTxt;
344	
345	  if (noEvents || mock || (noMatches && resourceEventStream)) {
346	    sysEventStatus = <NoEvents />;
347	  }
348	  if (noMatches && !resourceEventStream) {
349	    sysEventStatus = <NoMatchingEvents allCount={allCount} />;
350	  }
351	
352	  if (error) {
353	    statusBtnTxt = (
354	      <span className="co-sysevent-stream__connection-error">
355	        {_.isString(error)
356	          ? t('Error connecting to event stream: { error }', {
357	              error,
358	            })
359	          : t('Error connecting to event stream')}
360	      </span>
361	    );
362	    sysEventStatus = <ErrorLoadingEvents />;
363	  } else if (loading) {
364	    statusBtnTxt = <span>{t('Loading events...')}</span>;
365	    sysEventStatus = <Loading />;
366	  } else if (active) {
367	    statusBtnTxt = <span>{t('Streaming events...')}</span>;
368	  } else {
369	    statusBtnTxt = <span>{t('Event stream is paused.')}</span>;
370	  }
371	
372	  const klass = classNames('co-sysevent-stream__timeline', {
373	    'co-sysevent-stream__timeline--empty': !allCount || !count,
374	  });
375	  const messageCount =
376	    count < maxMessages
377	      ? t('Showing {{count}} event', { count })
378	      : t('Showing most recent {{count}} event', { count });
379	
380	  return (
381	    <PageSection isFilled variant="light">
382	      <div className="co-sysevent-stream">
383	        <div className="co-sysevent-stream__status">
384	          <div className="co-sysevent-stream__timeline__btn-text">
385	            {statusBtnTxt}
386	          </div>
387	          <div
388	            className="co-sysevent-stream__totals text-secondary"
389	            data-test="event-totals"
390	          >
391	            {messageCount}
392	          </div>
393	        </div>
394	
395	        <div className={klass}>
396	          <TogglePlay
397	            active={active}
398	            onClick={toggleStream}
399	            className="co-sysevent-stream__timeline__btn"
400	          />
401	          <div className="co-sysevent-stream__timeline__end-message">
402	            {t('Older events are not stored.')}
403	          </div>
404	        </div>
405	        {count > 0 && (
406	          <EventStreamList events={filteredEvents} EventComponent={Inner} />
407	        )}
408	        {sysEventStatus}
409	      </div>
410	    </PageSection>
411	  );
412	};
