430	const filterEvents = (messages, { kind, type, filter, textFilter }) => {
431	  // Don't use `fuzzy` because it results in some surprising matches in long event messages.
432	  // Instead perform an exact substring match on each word in the text filter.
433	  const words = _.uniq(_.toLower(textFilter).match(/\S+/g)).sort((a, b) => {
434	    // Sort the longest words first.
435	    return b.length - a.length;
436	  });
437	
438	  const textMatches = (obj) => {
439	    if (_.isEmpty(words)) {
440	      return true;
441	    }
442	    const name = _.get(obj, 'involvedObject.name', '');
443	    const message = _.toLower(obj.message);
444	    return _.every(
445	      words,
446	      (word) => name.indexOf(word) !== -1 || message.indexOf(word) !== -1,
447	    );
448	  };
449	
450	  const f = (obj) => {
451	    if (type && !typeFilter(type, obj)) {
452	      return false;
453	    }
454	    if (kind && !kindFilter(kind, obj)) {
455	      return false;
456	    }
457	    if (filter && !filter.some((flt) => flt(obj.involvedObject, obj))) {
458	      return false;
459	    }
460	    if (!textMatches(obj)) {
461	      return false;
462	    }
463	    return true;
464	  };
465	
466	  return _.filter(messages, f);
467	};
